  // Viewer: run in terminal
  ipcMain.on(
    "viewer:run-in-terminal",
    (_event, command: string) => {
      ctx.forwardToWebview(
        "terminal",
        "run-in-terminal",
        command,
      );
    },
  );

  // JSON-RPC methods
  registerMethod(
    "agent.sessionStart",
    (params) => {
      const p = params as {
        session_id: string;
        cwd: string;
        pty_session_id?: string;
