const cwd = '/Users/alexander/Projects/surface-shell/collab-electron';
const t1 = await mai.ticket({
  cwd,
  title: 'Fix pre-existing sidecar test failures under bun test',
  description: `Pre-existing test failures block week1 Section P verification even before the analytics/updater prune. Reproduced on a clean detached worktree at commit 3521562 (only UPSTREAM_BASE_SHA.txt added). Exact failures:\n\n- src/main/sidecar/client.test.ts\n  - \"creates session and receives data\" times out at line 145 because collected output never includes \"client-test\"\n  - \"lists sessions\" fails\n  - \"RPC timeout when server goes away\" times out\n  - \"reconnects session and receives scrollback\" times out at line 330 because output never includes \"RECONNECT_MARKER\"\n- src/main/sidecar/server.test.ts\n  - Bun throws \"describe() inside another test() is not yet implemented\" at line 254\n\nThe same failure cluster also poisons later full-suite runs with unhandled-error noise. This is pre-existing and unrelated to Section P.`,
  tags: 'surface-shell,pre-existing,test,sidecar,bun,week1-blocker',
  goal: 'Make the sidecar test files pass reliably under bun test on the week1-bitecs-substrate branch.',
  acceptanceCriteria: [
    'Running `bun test src/main/sidecar/client.test.ts src/main/sidecar/server.test.ts` passes from a clean checkout.',
    'client.test.ts session-output assertions become deterministic instead of timing out at lines 145 and 330.',
    'server.test.ts no longer uses a structure that Bun rejects with nested describe/test semantics.',
    'A full `bun test` run no longer emits unhandled-error spillover from the sidecar suites.'
  ],
  verification: [
    'From a clean checkout, run `bun test src/main/sidecar/client.test.ts src/main/sidecar/server.test.ts`.',
    'Then run full `bun test` and confirm the sidecar-related unhandled-error noise is gone.'
  ]
});
const t2 = await mai.ticket({
  cwd,
  title: 'Fix pre-existing DOM-less shell tests under bun test',
  description: `Pre-existing renderer-unit tests assume browser globals without providing a DOM harness. Reproduced on a clean detached worktree at commit 3521562. Exact failures:\n\n- src/windows/shell/src/canvas-viewport.test.ts fails because importing canvas-viewport.js immediately reads window.shellApi.getPlatform() and Bun reports \"window is not defined\" at line 7 of canvas-viewport.js.\n- src/windows/shell/src/panel-manager.test.ts fails in beforeEach because Bun reports \"document is not defined\" at line 23.\n\nThese failures are unrelated to the analytics/updater prune and block week1 Section P test verification.`,
  tags: 'surface-shell,pre-existing,test,renderer,bun,week1-blocker',
  goal: 'Make the shell renderer unit tests runnable under bun test with an explicit DOM/window harness or equivalent refactor.',
  acceptanceCriteria: [
    'Running `bun test src/windows/shell/src/canvas-viewport.test.ts src/windows/shell/src/panel-manager.test.ts` passes from a clean checkout.',
    'canvas-viewport.js no longer crashes at module import time in a non-browser test environment.',
    'panel-manager.test.ts has a valid DOM available before beforeEach touches document.body.'
  ],
  verification: [
    'From a clean checkout, run `bun test src/windows/shell/src/canvas-viewport.test.ts src/windows/shell/src/panel-manager.test.ts`.',
    'Then run full `bun test` and confirm these suites no longer fail with window/document ReferenceErrors.'
  ]
});
console.log(JSON.stringify({ t1, t2 }, null, 2));

